// Generado automáticamente a partir de los archivos .jpeg/.gif en esta misma carpeta.
// Se embeben como base64 (no como import de asset de Vite) porque pdfmake necesita
// data URIs directas para 'background'/'image' — un import normal de Vite da una URL,
// y ya tuvimos problemas de CORS/redirecciones con URLs remotas para pdfmake en este proyecto.

export const MEMBRETE_FONDO_BASE64 = 'data:image/jpeg;base64,';
export const MEMBRETE_ICONO_FOOTER_BASE64 = 'data:image/gif;base64,';
